import React from 'react';
import Layout from '../components/Layout.jsx';
import {makeStyles} from "@material-ui/core/styles";

const useStyles = makeStyles((theme) => ({
    workItem: {
        marginTop: '1rem',
        paddingBottom: '1rem',
        borderBottom: '1px solid white',
    },
    workTitle: {
        fontWeight: 'bold'
    },
    jobTitle: {
        fontWeight: 'bold',
        display: 'inline-block'
    },
    sectionTitle: {
        marginTop: '1.5rem',
        marginBottom: '0.5rem'
    },
    paragraph: {
        whiteSpace: 'pre-wrap'
    }
}));

const Work = ({user}) => {
    const classes = useStyles();
    return (
        <Layout user={user}>
            <div>
                <h3 className={classes.sectionTitle}>Work</h3>
                <ul>
                    {user.work.map((work, i) => (
                        <li className={classes.workItem} key={i}>
                            <h4 className={classes.workTitle}>{work.position}</h4>
                            <div>
                                <p className={classes.jobTitle}>{work.company}</p> <span>{work.location}</span>
                                <span> &sdot; </span>
                                <span>
                  {work.end.year ? `${work.start.year} to ${work.end.year}` : `since ${work.start.year}`}
                </span>
                            </div>
                            <p className={classes.paragraph}>{work.summary}</p>
                        </li>
                    ))}
                </ul>
            </div>
        </Layout>
    );
};

export default Work;
