import React from 'react';
import Layout from '../components/Layout.jsx';
import {makeStyles} from "@material-ui/core/styles";
import Chip from "@material-ui/core/Chip";

const useStyles = makeStyles((theme) => ({
    profileLink: {
        marginRight: '0.5rem',
        marginBottom: '0.5rem',
        display: 'inline-block',
        fontSize: '18px'
    },
    sectionTitle: {
        marginTop: '1.5rem',
        marginBottom: '0.5rem'
    },
    paragraph: {
        whiteSpace: 'pre-wrap'
    },
    chipWrapper: {
        display: 'flex',
        justifyContent: 'center',
        flexWrap: 'wrap',
        '& > *': {
            margin: theme.spacing(0.5),
        },
    }
}));

const Me = ({user}) => {
    const classes = useStyles();
    return (
        <Layout user={user}>
            <div>
                <h3 className={classes.sectionTitle}>About Me</h3>
                <p className={classes.paragraph}>{user.basics.summary}</p>
            </div>
            <div>
                <h3 className={classes.sectionTitle}>Skills</h3>
                <div className={classes.chipWrapper}>
                    {user.skills.map(skill => (
                        <Chip key={skill.name} label={skill.name}/>
                    ))}
                </div>
            </div>
            <div>
                <h3 className={classes.sectionTitle}>Profiles</h3>
                <ul>
                    {user.basics.profiles.map((profile, i) => (
                        <li className={classes.profileLink} key={profile.network}>
                            {i !== 0 && ' | '}
                            <a href={profile.url} target="_blank" rel="noreferrer noopener">
                                {profile.network}
                            </a>
                        </li>
                    ))}
                </ul>
            </div>
        </Layout>
    );
};

export default Me;
