import React from 'react';
import Layout from '../components/Layout.jsx';
import {makeStyles} from "@material-ui/core/styles";

const useStyles = makeStyles((theme) => ({
    educationItem: {
        marginTop: '1rem',
        paddingBottom: '1rem',
        borderBottom: '1px solid white',
    },
    institution: {
        fontWeight: 'bold'
    },
    degree: {
        fontWeight: 'bold',
        display: 'inline-block'
    },
    sectionTitle: {
        marginTop: '1.5rem',
        marginBottom: '0.5rem'
    },
    paragraph: {
        whiteSpace: 'pre-wrap'
    }
}));

const Education = ({user}) => {
    const classes = useStyles();
    return (
        <Layout user={user}>
            <div>
                <h3 className={classes.sectionTitle}>Education</h3>
                <ul>
                    {user.education.map((education, i) => (
                        <li className={classes.educationItem} key={i}>
                            <h4 className={classes.institution}>{education.position}</h4>
                            <div>
                                <p className={classes.degree}>
                                    {education.studyType}, {education.area}
                                </p>{' '}
                                <span> &sdot; </span>
                                <span>
                  {education.start.year} to {education.end.year}
                </span>
                            </div>
                            <p className={classes.paragraph}>{education.description.replace('\n\n', '\n')}</p>
                        </li>
                    ))}
                </ul>
            </div>
        </Layout>
    );
};

export default Education;
